class Graph {
    constructor() {
        this.adjacencyList = {};
    }

    addVertex(vertex) {
        if (!this.adjacencyList[vertex]) {
            this.adjacencyList[vertex] = [];
        }
    }

    addEdge(vertex1, vertex2) {
        this.adjacencyList[vertex1].push(vertex2);
        this.adjacencyList[vertex2].push(vertex1); // For undirected graph
    }

    DFS(startingVertex) {
        const visited = {};
        const stack = [startingVertex];

        while (stack.length > 0) {
            const vertex = stack.pop();
            if (!visited[vertex]) {
                console.log(vertex);
                visited[vertex] = true;
                this.adjacencyList[vertex].forEach(neighbor => {
                    if (!visited[neighbor]) {
                        stack.push(neighbor);
                    }
                });
            }
        }
    }
}

// Example usage:
const graph = new Graph();
graph.addVertex('A');
graph.addVertex('B');
graph.addVertex('C');
graph.addVertex('D');
graph.addEdge('A', 'B');
graph.addEdge('A', 'C');
graph.addEdge('B', 'D');
graph.addEdge('C', 'D');

console.log("DFS Traversal starting from vertex A:");
graph.DFS('A');
```

### Explanation:
1. **Graph Class**:
   - `adjacencyList`: An object to store the adjacency list of each vertex.

2. **Add Vertex (`Graph::addVertex(vertex)`)**:
   - Adds a new vertex to the graph if it doesn't already exist.

3. **Add Edge (`Graph::addEdge(vertex1, vertex2)`)**:
   - Adds an edge between two vertices in the graph. For an undirected graph, both directions are added.

4. **DFS Traversal (`Graph::DFS(startingVertex)`)**:
   - Uses a stack to perform DFS traversal starting from the given vertex.
   - Marks each visited vertex and prints it.
   - Recursively visits all unvisited neighbors of the current vertex.

